import{_ as e,o as l,c as a,a2 as n}from"./chunks/framework.Pywvta2k.js";const f=JSON.parse('{"title":"四圣心源","description":"","frontmatter":{},"headers":[],"relativePath":"tcm-data/04-明清/02-四圣心源（黄元御）.md","filePath":"tcm-data/04-明清/02-四圣心源（黄元御）.md","lastUpdated":1781084559000}'),r={name:"tcm-data/04-明清/02-四圣心源（黄元御）.md"};function o(s,t,d,i,g,h){return l(),a("div",null,[...t[0]||(t[0]=[n(`<h1 id="四圣心源" tabindex="-1">四圣心源 <a class="header-anchor" href="#四圣心源" aria-label="Permalink to &quot;四圣心源&quot;">​</a></h1><blockquote><p>黄元御（1705-1758年），山东昌邑人 尊经派代表人物，清代最伟大的医家之一 代表作：《四圣心源》《伤寒悬解》《金匮悬解》《长沙药解》</p></blockquote><hr><h2 id="一、基本信息" tabindex="-1">一、基本信息 <a class="header-anchor" href="#一、基本信息" aria-label="Permalink to &quot;一、基本信息&quot;">​</a></h2><ul><li><strong>字号</strong>：名玉璐，字元御，号研农、玉楸子</li><li><strong>生平</strong>：30岁时因用眼过度被庸医治瞎一眼，从此发愤学医</li><li><strong>著作</strong>：黄元御医书八种（《四圣心源》《素灵微蕴》《伤寒悬解》《金匮悬解》《伤寒说意》《长沙药解》《玉楸药解》《灵枢解》）</li><li><strong>学术地位</strong>：<strong>&quot;四圣&quot;集大成者</strong>—黄帝、岐伯、越人、仲景</li></ul><h3 id="核心思想" tabindex="-1">核心思想 <a class="header-anchor" href="#核心思想" aria-label="Permalink to &quot;核心思想&quot;">​</a></h3><blockquote><p><strong>「医有黄帝、岐伯、越人、仲景四圣之书，争光日月。」</strong><strong>「人无不病，病无不死，而医之为道，乃在生死之间。」</strong><strong>「四圣之外，皆旁门也。」</strong></p></blockquote><p>黄元御对唐宋以后的医家基本持否定态度，认为只有回归&quot;四圣&quot;（《内经》《难经》《伤寒论》《金匮要略》）才是正途。</p><hr><h2 id="二、核心理论-一气周流-土枢四象" tabindex="-1">二、核心理论：一气周流，土枢四象 <a class="header-anchor" href="#二、核心理论-一气周流-土枢四象" aria-label="Permalink to &quot;二、核心理论：一气周流，土枢四象&quot;">​</a></h2><h3 id="_1-中气如轴-四维如轮" tabindex="-1">1. 中气如轴，四维如轮 <a class="header-anchor" href="#_1-中气如轴-四维如轮" aria-label="Permalink to &quot;1. 中气如轴，四维如轮&quot;">​</a></h3><blockquote><p><strong>「中气者，阴阳升降之枢轴也。」</strong><strong>「脾为己土，以太阴而主升；胃为戊土，以阳明而主降。升降之权，则在阴阳之交，是谓中气。」</strong></p></blockquote><p><strong>模型</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>        心（火）</span></span>
<span class="line"><span>           ↑ 降</span></span>
<span class="line"><span>    肝（木） ← 中土（轴） → 肺（金）</span></span>
<span class="line"><span>           ↓ 升</span></span>
<span class="line"><span>        肾（水）</span></span></code></pre></div><ul><li><strong>左升</strong>：肝木（血）左升 → 心火（神）化生 ← 肾水温升以养肝木</li><li><strong>右降</strong>：肺金（气）右降 → 肾水（精）封藏 ← 心火清降以温肺金</li><li><strong>中轴</strong>：脾胃（土）居中，为升降的枢纽</li></ul><h3 id="_2-水寒土湿木郁-——-万病之源" tabindex="-1">2. 水寒土湿木郁 —— 万病之源 <a class="header-anchor" href="#_2-水寒土湿木郁-——-万病之源" aria-label="Permalink to &quot;2. 水寒土湿木郁 —— 万病之源&quot;">​</a></h3><blockquote><p><strong>「凡病之起，无不因于水寒土湿，木气不达。」</strong></p></blockquote><p>黄元御认为90%以上的疾病都源于这个核心病机：</p><table tabindex="0"><thead><tr><th style="text-align:left;">环节</th><th style="text-align:left;">含义</th><th style="text-align:left;">对应症状</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>水寒</strong></td><td style="text-align:left;">肾阳不足，下焦寒凝</td><td style="text-align:left;">腰凉、脚冷、夜尿多</td></tr><tr><td style="text-align:left;"><strong>土湿</strong></td><td style="text-align:left;">脾阳不振，湿浊内停</td><td style="text-align:left;">腹胀、便溏、面色暗沉</td></tr><tr><td style="text-align:left;"><strong>木郁</strong></td><td style="text-align:left;">肝气不升，郁而化火</td><td style="text-align:left;">烦躁、血压高、目干涩</td></tr></tbody></table><p><strong>这正是普光师兄的核心病机。</strong></p><h3 id="_3-阳尊阴卑-——-崇阳抑阴" tabindex="-1">3. 阳尊阴卑 —— 崇阳抑阴 <a class="header-anchor" href="#_3-阳尊阴卑-——-崇阳抑阴" aria-label="Permalink to &quot;3. 阳尊阴卑 —— 崇阳抑阴&quot;">​</a></h3><blockquote><p><strong>「病于阴虚者，千百之一；病于阳虚者，尽人皆是也。」</strong></p></blockquote><p>这与朱震亨&quot;阳常有余，阴常不足&quot;几乎相反。黄元御认为：<strong>阳气是人生命活动的根本，阴邪（寒湿）是致病的主要原因。</strong></p><h3 id="_4-六经气化-——-六经来自五脏" tabindex="-1">4. 六经气化 —— 六经来自五脏 <a class="header-anchor" href="#_4-六经气化-——-六经来自五脏" aria-label="Permalink to &quot;4. 六经气化 —— 六经来自五脏&quot;">​</a></h3><p>黄元御发展了《伤寒论》的六经理论，认为：</p><ul><li>太阳 → 膀胱（寒水）→ 病则水寒</li><li>阳明 → 胃（燥金）→ 病则燥热</li><li>少阳 → 胆（相火）→ 病则火郁</li><li>太阴 → 脾（湿土）→ 病则湿盛（核心）</li><li>少阴 → 肾（君火）→ 病则寒化或热化</li><li>厥阴 → 肝（风木）→ 病则风动</li></ul><hr><h2 id="三、核心方剂" tabindex="-1">三、核心方剂 <a class="header-anchor" href="#三、核心方剂" aria-label="Permalink to &quot;三、核心方剂&quot;">​</a></h2><h3 id="基础方-黄芽汤-万方之祖" tabindex="-1">基础方：黄芽汤（万方之祖） <a class="header-anchor" href="#基础方-黄芽汤-万方之祖" aria-label="Permalink to &quot;基础方：黄芽汤（万方之祖）&quot;">​</a></h3><blockquote><p><strong>「中气之治，崇阳补火，则宜参、姜；培土泄水，则宜甘、苓。」</strong></p></blockquote><table tabindex="0"><thead><tr><th style="text-align:left;">药物</th><th style="text-align:left;">剂量（原方）</th><th style="text-align:left;">功用</th></tr></thead><tbody><tr><td style="text-align:left;">人参</td><td style="text-align:left;">三钱（约9g）</td><td style="text-align:left;">补中气，崇阳</td></tr><tr><td style="text-align:left;">炙甘草</td><td style="text-align:left;">二钱（约6g）</td><td style="text-align:left;">培土和中</td></tr><tr><td style="text-align:left;">茯苓</td><td style="text-align:left;">二钱（约6g）</td><td style="text-align:left;">泄湿燥土</td></tr><tr><td style="text-align:left;">干姜</td><td style="text-align:left;">二钱（约6g）</td><td style="text-align:left;">温脾散寒</td></tr></tbody></table><p><strong>几乎所有黄元御的方子都是黄芽汤的加减。</strong></p><h3 id="劳伤解系列方-普光处方的主要来源" tabindex="-1">劳伤解系列方（普光处方的主要来源） <a class="header-anchor" href="#劳伤解系列方-普光处方的主要来源" aria-label="Permalink to &quot;劳伤解系列方（普光处方的主要来源）&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">方名</th><th style="text-align:left;">组成（黄芽汤加味）</th><th style="text-align:left;">主治</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>天魂汤</strong></td><td style="text-align:left;">黄芽汤 + 桂枝、附子</td><td style="text-align:left;">水寒土湿，阳不升</td></tr><tr><td style="text-align:left;"><strong>地魄汤</strong></td><td style="text-align:left;">甘草、半夏、麦冬、芍药、五味子、元参、牡蛎</td><td style="text-align:left;">肺胃不降，相火上炎</td></tr><tr><td style="text-align:left;"><strong>金鼎汤</strong></td><td style="text-align:left;">甘草、茯苓、半夏、桂枝、芍药、龙骨、牡蛎</td><td style="text-align:left;">惊悸，相火不藏</td></tr><tr><td style="text-align:left;"><strong>乌肝汤</strong></td><td style="text-align:left;">黄芽汤 + 附子、首乌、芍药、桂枝</td><td style="text-align:left;">肝血虚弱</td></tr><tr><td style="text-align:left;"><strong>兔髓汤</strong></td><td style="text-align:left;">黄芽汤 + 附子、五味子</td><td style="text-align:left;">肾阳虚，精气不固</td></tr><tr><td style="text-align:left;"><strong>玉池汤</strong></td><td style="text-align:left;">甘草、茯苓、半夏、桂枝、芍药、龙骨、牡蛎、菟丝子</td><td style="text-align:left;">遗精滑泄</td></tr></tbody></table><h3 id="杂病解常用方" tabindex="-1">杂病解常用方 <a class="header-anchor" href="#杂病解常用方" aria-label="Permalink to &quot;杂病解常用方&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">方名</th><th style="text-align:left;">组成</th><th style="text-align:left;">主治</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>苓桂半夏汤</strong></td><td style="text-align:left;">茯苓、桂枝、半夏、甘草</td><td style="text-align:left;">胃气上逆</td></tr><tr><td style="text-align:left;"><strong>姜苓半夏汤</strong></td><td style="text-align:left;">干姜、茯苓、半夏、甘草</td><td style="text-align:left;">呕吐</td></tr><tr><td style="text-align:left;"><strong>桂枝丹皮首乌汤</strong></td><td style="text-align:left;">桂枝、丹皮、首乌、甘草、茯苓、半夏、干姜</td><td style="text-align:left;">肝血瘀滞</td></tr><tr><td style="text-align:left;"><strong>郁李仁丹皮汤</strong></td><td style="text-align:left;">郁李仁、丹皮、甘草、茯苓、桂枝、白芍</td><td style="text-align:left;">癥瘕</td></tr><tr><td style="text-align:left;"><strong>泽泻汤</strong></td><td style="text-align:left;">泽泻、白术</td><td style="text-align:left;">水饮眩冒</td></tr></tbody></table><hr><h2 id="四、经典名言精选" tabindex="-1">四、经典名言精选 <a class="header-anchor" href="#四、经典名言精选" aria-label="Permalink to &quot;四、经典名言精选&quot;">​</a></h2><h3 id="论中气" tabindex="-1">论中气 <a class="header-anchor" href="#论中气" aria-label="Permalink to &quot;论中气&quot;">​</a></h3><blockquote><p><strong>「中气者，阴阳升降之枢轴也。」</strong><strong>「中气衰则升降窒，四维皆病。」</strong><strong>「脾升则肾肝亦升，故水木不郁；胃降则心肺亦降，故金火不滞。」</strong></p></blockquote><h3 id="论疾病总纲" tabindex="-1">论疾病总纲 <a class="header-anchor" href="#论疾病总纲" aria-label="Permalink to &quot;论疾病总纲&quot;">​</a></h3><blockquote><p><strong>「凡病之起，无不因于水寒土湿，木气不达。」</strong><strong>「十人之中，湿居八九而不止也。」</strong><strong>「病于阴虚者，千百之一；病于阳虚者，尽人皆是也。」</strong></p></blockquote><h3 id="论治法" tabindex="-1">论治法 <a class="header-anchor" href="#论治法" aria-label="Permalink to &quot;论治法&quot;">​</a></h3><blockquote><p><strong>「崇阳补火，则宜参、姜；培土泄水，则宜甘、苓。」</strong><strong>「泻热而热不清，滋水而水愈旺。」</strong>（批评滥用寒凉滋阴） <strong>「人以阳气为生，医以扶阳为急。」</strong></p></blockquote><h3 id="论水火" tabindex="-1">论水火 <a class="header-anchor" href="#论水火" aria-label="Permalink to &quot;论水火&quot;">​</a></h3><blockquote><p><strong>「火降则水不下寒，水升则火不上热。」</strong><strong>「水寒则土湿，土湿则木郁。」</strong></p></blockquote><h3 id="论用药" tabindex="-1">论用药 <a class="header-anchor" href="#论用药" aria-label="Permalink to &quot;论用药&quot;">​</a></h3><blockquote><p><strong>「诸药之中，附子为最，能回阳于垂绝。」</strong><strong>「桂、附、姜、辛——扶阳之要药。」</strong></p></blockquote><hr><h2 id="五、对后世的影响" tabindex="-1">五、对后世的影响 <a class="header-anchor" href="#五、对后世的影响" aria-label="Permalink to &quot;五、对后世的影响&quot;">​</a></h2><h3 id="彭子益《圆运动的古中医学》" tabindex="-1">彭子益《圆运动的古中医学》 <a class="header-anchor" href="#彭子益《圆运动的古中医学》" aria-label="Permalink to &quot;彭子益《圆运动的古中医学》&quot;">​</a></h3><p>黄元御的&quot;一气周流&quot;模型被彭子益直接继承并发展为&quot;圆运动&quot;理论。两者的核心模型几乎一致，彭子益在用药上更偏向温补（如重用附子）。</p><h3 id="李可老中医" tabindex="-1">李可老中医 <a class="header-anchor" href="#李可老中医" aria-label="Permalink to &quot;李可老中医&quot;">​</a></h3><p>李可称黄元御为&quot;医圣&quot;，其<strong>温氏奔豚汤</strong>、<strong>破格救心汤</strong>等名方的底层逻辑就是黄元御的&quot;水寒土湿木郁&quot;模型。</p><h3 id="倪海厦" tabindex="-1">倪海厦 <a class="header-anchor" href="#倪海厦" aria-label="Permalink to &quot;倪海厦&quot;">​</a></h3><p>倪海厦在教学中高度推崇黄元御，多次引用《四圣心源》的&quot;水寒土湿木郁&quot;理论来解释现代病。</p><h3 id="现代评价" tabindex="-1">现代评价 <a class="header-anchor" href="#现代评价" aria-label="Permalink to &quot;现代评价&quot;">​</a></h3><ul><li>拥趸者：认为黄元御是继张仲景之后最伟大的医家</li><li>批评者：认为他过于排斥后世医家，用药偏温燥</li><li><strong>客观评价</strong>：黄元御在理论上建立了最简洁优美的&quot;一气周流&quot;模型，在临床上对阳虚寒湿证的疗效极佳。但其理论对阴虚证、温病等的解释力不足，需要与其他流派互补。</li></ul><hr><h2 id="六、黄元御与普光师兄处方的对应" tabindex="-1">六、黄元御与普光师兄处方的对应 <a class="header-anchor" href="#六、黄元御与普光师兄处方的对应" aria-label="Permalink to &quot;六、黄元御与普光师兄处方的对应&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">普光症状</th><th style="text-align:left;">四圣心源病机</th><th style="text-align:left;">对应方剂</th></tr></thead><tbody><tr><td style="text-align:left;">面色暗沉、腰腹凉</td><td style="text-align:left;">土湿水寒</td><td style="text-align:left;">黄芽汤（参姜苓草）</td></tr><tr><td style="text-align:left;">头发花白、目干涩</td><td style="text-align:left;">肝血不足，木郁</td><td style="text-align:left;">乌肝汤法（当归、首乌）</td></tr><tr><td style="text-align:left;">血压高、前胸出汗</td><td style="text-align:left;">相火不降</td><td style="text-align:left;">金鼎汤法（龙牡芍）</td></tr><tr><td style="text-align:left;">阴囊潮湿、脚痒</td><td style="text-align:left;">湿浊下注</td><td style="text-align:left;">泽泻、黄柏</td></tr><tr><td style="text-align:left;">脚后跟开裂</td><td style="text-align:left;">肾经不足</td><td style="text-align:left;">牛膝引经</td></tr></tbody></table><p><strong>您的处方&quot;温潜黄芽天魂汤&quot;正是以上思路的融合。</strong></p><hr><p><em>本条目为精简框架版。可扩展至黄元御医书八种逐本详解、劳伤解逐方分析、黄元御与各家（尤其李东垣、朱震亨）的对比等专题。</em></p>`,64)])])}const u=e(r,[["render",o]]);export{f as __pageData,u as default};
